import React, { useState } from 'react';
import './Services.css';
import Footer from './Footer';
import P1 from '../assests/core2.png';
import Blog from './Blog';
import Contact from './Contact';

const teamMembers = [
  { id: 1, name: 'Prof. Joy Chowdhury', role: 'Managing Director and CEO of Kairos Learning Universe', image: P1, description: 'Prof. Joy Chowdhury is the Managing Director and CEO of Kairos Learning Universe. He is an eminent Learning and development professional, a motivator, and an emotional intelligence Coach. He has interacted, imparted and managed inter-disciplinary training for multiple clients across the globe. His professional stint encompasses a variety of Corporates and Academic Institutions as Vice President and Directorship. He has been awarded Icon of India by Business Talkz in 2024. A Guest Lecturer with multiple universities across Europe and India. Had been an integral part and led teams on educational projects and global knowledge transition. Innovative and experienced strategic leader with expertise in project management and creative problem-solving. Skilled in managing complex training, educational and knowledge management projects and innovative solution development. Committed to creating engaging and meaningful content for learners. A well-acclaimed motivational speaker and author. He is an experienced thought leader with expertise in project management and creative problem-solving. Skilled in project coordination, training management and innovative solution development. Detail-oriented team player with strong organizational skills. Ability to handle multiple projects simultaneously with a high degree of accuracy.', social: { facebook: '#', twitter: '#', google: '#' } },
  { id: 2, name: 'Kristiana', role: 'Web Designer', image: P1, description: 'Creative UI designer specializing in responsive and interactive designs.', social: { facebook: '#', twitter: '#', google: '#' } },
  { id: 3, name: 'John Doe', role: 'UI/UX Designer', image: P1, description: 'Passionate about user experience and intuitive interfaces.', social: { facebook: '#', twitter: '#', google: '#' } },
  { id: 4, name: 'Jane Smith', role: 'Frontend Developer', image: P1, description: 'Expert in JavaScript frameworks and modern front-end technologies.', social: { facebook: '#', twitter: '#', google: '#' } },
  { id: 5, name: 'Alice Johnson', role: 'Backend Developer', image: P1, description: 'Specialized in building robust and scalable back-end solutions.', social: { facebook: '#', twitter: '#', google: '#' } },
  { id: 6, name: 'Bob Brown', role: 'Full Stack Developer', image: P1, description: 'Full stack expertise in both front-end and back-end development.', social: { facebook: '#', twitter: '#', google: '#' } },
];

const Services = () => {
  const [selectedMember, setSelectedMember] = useState(null);

  const openPopup = (member) => setSelectedMember(member);
  const closePopup = () => setSelectedMember(null);

  return (
    <div className='services'>
      <div className="our-team-heading">
        <h1>OUR TEAM</h1>
      </div>
      <div className="team-container">
        {teamMembers.map((member) => (
          <div className="team-member" key={member.id}>
            <div className="our-team">
              <img src={member.image} alt={member.name} />
              <div className="team-content">
                <h3 className="title">{member.name}</h3>
                <span className="post">{member.role}</span>
                <ul className="social">
                  <li><a href={member.social.facebook}><i className="fab fa-facebook-f"></i></a></li>
                  <li><a href={member.social.twitter}><i className="fab fa-twitter"></i></a></li>
                  <li><a href={member.social.google}><i className="fab fa-google-plus-g"></i></a></li>
                </ul>
                <button className="show-more-btn" onClick={() => openPopup(member)}>Show More</button>
              </div>
            </div>
          </div>
        ))}
      </div>
      {selectedMember && (
        <div className="popup-overlay" onClick={closePopup}>
          <div className="popup-content" onClick={(e) => e.stopPropagation()}>
            <span className="close-btn" onClick={closePopup}>&times;</span>
            <img src={selectedMember.image} alt={selectedMember.name} className="popup-img" />
            <h2>{selectedMember.name}</h2>
            <h4>{selectedMember.role}</h4>
            <p>{selectedMember.description}</p>
          </div>
        </div>
      )}
      <Blog/>
      <Contact/>
      <Footer />
    </div>
  );
};

export default Services;
